#include <stdio.h>

float calculerSurface(float longueur, float hauteur) {
    return longueur * hauteur;
}

int main() {
    float L, H, surface;

    printf("Entrez la longueur du mur (en metres) : ");
    scanf("%f", &L);
    printf("Entrez la hauteur du mur (en metres) : ");
    scanf("%f", &H);

    surface = calculerSurface(L, H);

    printf("La surface du mur est de %.2f metres carres.\n", surface);

    return 0;
}
